268	    if (filter.entityId) {
269	      conditions.push('entity_id = ?');
270	      params.push(filter.entityId);
271	    }
272	    if (filter.factId) {
273	      conditions.push('fact_id = ?');
274	      params.push(filter.factId);
275	    }
276	    if (filter.source && filter.source.length > 0) {
277	      conditions.push(`source IN (${filter.source.map(() => '?').join(',')})`);
278	      params.push(...filter.source);
279	    }
280	    if (filter.minConfidence !== undefined) {
281	      conditions.push('confidence >= ?');
282	      params.push(filter.minConfidence);
283	    }
284	    if (filter.atChapter !== undefined) {
285	      conditions.push('known_since <= ?');
286	      params.push(filter.atChapter);
287	    }
288	
289	    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
290	    const rows = this.db.prepare(
291	      `SELECT * FROM knowledge ${whereClause} ORDER BY known_since DESC, rowid DESC`
292	    ).all(...params) as KnowledgeRow[];
293	
294	    return rows.map(r => this.rowToKnowledge(r));
295	  }
