312	   * 如果基础 ID 已存在（同章节内 seal/restore/decay 重复操作），
313	   * 追加两位数字序号（_02, _03...）。
314	   */
315	  private generateId(entityId: string, factId: string): string {
316	    const knower = entityId.replace('ent_', '');
317	    const factRef = factId.replace('fct_', '');
318	    const baseId = `kno_${knower}_${factRef}`;
319	
320	    // 检查基础 ID 是否已占用
321	    const existing = this.db.prepare('SELECT COUNT(*) as cnt FROM knowledge WHERE id = ?').get(baseId) as { cnt: number };
322	    if (existing.cnt === 0) {
323	      return baseId;
324	    }
325	
326	    // 基础 ID 已占用，追加序号
327	    let seq = 2;
328	    while (true) {
329	      const seqId = `${baseId}_${String(seq).padStart(2, '0')}`;
330	      const check = this.db.prepare('SELECT COUNT(*) as cnt FROM knowledge WHERE id = ?').get(seqId) as { cnt: number };
331	      if (check.cnt === 0) return seqId;
332	      seq++;
333	    }
334	  }
335	
336	  /**
337	   * 将 SQLite 行转换为 Knowledge 对象
338	   */
339	  private rowToKnowledge(row: KnowledgeRow): Knowledge {
340	    return {
341	      id: row.id,
342	      factId: row.fact_id,
343	      entityId: row.entity_id,
344	      knownSince: row.known_since,
345	      source: row.source as KnowledgeSource,
346	      confidence: row.confidence,
347	      previousConfidence: row.previous_confidence ?? undefined,
348	      updatedAtEvent: row.updated_at_event ?? undefined,
349	    };
350	  }
351	}
