// =============================================================================
// SQLiteKnowledgeStoreAdapter —— KnowledgeStore 接口的 SQLite 实现
// =============================================================================
// Phase 1 最小版本：表结构 + create / batchCreate / getLatest / getByFactId。
// seal/restore/decay/soul_read/implant 的写入编排由 ProposalManager 在 Phase B 完成。
//
// 设计原则：
//   - Event Sourcing 不可变：永远不 DELETE / UPDATE knowledge 表记录，只 INSERT 新记录
//   - "取最新"查询：ORDER BY known_since DESC, rowid DESC LIMIT 1
//   - rowid tiebreaker：同章节内显式操作（seal/implant）晚于自动推导（propagation）
//   - 与 FactStore 共享同一个 SQLite 连接（同库不同表）
//
// 与架构文档的对应关系：
//   §3.6  Knowledge 双流写入     → 与 Fact 流并行的认知事件流
//   §4.3.4 KnowledgeStore 接口    → 完整接口定义
//   §10.1 写入流                  → Phase B 事务内原子写入
//   附录 E.7 knowledge 表         → DDL 已在 FactStore 适配器中创建
// =============================================================================

import type Database from 'better-sqlite3';
import type { Knowledge, KnowledgeFilter, KnowledgeSource } from '../../types.js';

// ---------------------------------------------------------------------------
// SQLite 行类型
// ---------------------------------------------------------------------------

interface KnowledgeRow {
  id: string;
  fact_id: string;
  entity_id: string;
  known_since: number;
  source: string;
  confidence: number;
  previous_confidence: number | null;
  updated_at_event: string | null;
}

// ---------------------------------------------------------------------------
// SQLiteKnowledgeStoreAdapter
// ---------------------------------------------------------------------------

export class SQLiteKnowledgeStoreAdapter {
  private db: Database.Database;

  /**
   * @param db 共享的 better-sqlite3 Database 实例（与 FactStore 同库）
   *           DDL 已由 SQLiteFactStoreAdapter 在初始化时创建
   */
  constructor(db: Database.Database) {
    this.db = db;
  }

  // -----------------------------------------------------------------------
  // 写入操作
  // -----------------------------------------------------------------------

  /**
   * 创建单条 Knowledge 记录
   *
   * 自动生成 ID：kno_{knower}_{factSeq}
   * knower 为 entityId 去掉 ent_ 前缀的部分
   * factSeq 为 factId 去掉 fct_ 前缀的部分
   */
  create(knowledge: Omit<Knowledge, 'id'>): Knowledge {
    const id = this.generateId(knowledge.entityId, knowledge.factId);

    this.db.prepare(`
      INSERT INTO knowledge (id, fact_id, entity_id, known_since, source, confidence, previous_confidence, updated_at_event)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      id,
      knowledge.factId,
      knowledge.entityId,
      knowledge.knownSince,
      knowledge.source,
      knowledge.confidence,
      knowledge.previousConfidence ?? null,
      knowledge.updatedAtEvent ?? null,
    );

    return this.rowToKnowledge(
      this.db.prepare('SELECT * FROM knowledge WHERE id = ?').get(id) as KnowledgeRow
    );
  }

  /**
   * 批量创建 Knowledge 记录（commit_event 时一次性写入多条）
   *
   * 所有记录在同一事务中写入，保证原子性。
   */
  batchCreate(entries: Omit<Knowledge, 'id'>[]): Knowledge[] {
    const stmt = this.db.prepare(`
      INSERT INTO knowledge (id, fact_id, entity_id, known_since, source, confidence, previous_confidence, updated_at_event)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `);

    const results: Knowledge[] = [];
    for (const entry of entries) {
      const id = this.generateId(entry.entityId, entry.factId);
      stmt.run(
        id,
        entry.factId,
        entry.entityId,
        entry.knownSince,
        entry.source,
        entry.confidence,
        entry.previousConfidence ?? null,
        entry.updatedAtEvent ?? null,
      );
      // 回读已写入的记录（同一事务内可见）
      const row = this.db.prepare('SELECT * FROM knowledge WHERE id = ?').get(id) as KnowledgeRow;
      results.push(this.rowToKnowledge(row));
    }

    return results;
  }

  // -----------------------------------------------------------------------
  // 查询操作
  // -----------------------------------------------------------------------

  /**
   * 查询某实体在指定章节知道的所有 Fact（取最新一条 Knowledge 记录的 confidence > 0）
   *
   * "取最新"查询模板：
   *   WHERE entity_id = ? AND known_since <= ? ORDER BY known_since DESC, rowid DESC LIMIT 1
   */
  getKnownFacts(entityId: string, atChapter?: number): Knowledge[] {
    // 使用子查询：对每个 (entity_id, fact_id) 组合取最新一条
    let sql: string;
    const params: unknown[] = [entityId];

    if (atChapter !== undefined) {
      sql = `
        SELECT k.* FROM knowledge k
        INNER JOIN (
          SELECT entity_id, fact_id, MAX(known_since) as max_known, MAX(rowid) as max_rowid
          FROM knowledge
          WHERE entity_id = ? AND known_since <= ?
          GROUP BY entity_id, fact_id
        ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
                  AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
        WHERE k.confidence > 0
      `;
      params.push(atChapter);
    } else {
      sql = `
        SELECT k.* FROM knowledge k
        INNER JOIN (
          SELECT entity_id, fact_id, MAX(known_since) as max_known, MAX(rowid) as max_rowid
          FROM knowledge
          WHERE entity_id = ?
          GROUP BY entity_id, fact_id
        ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
                  AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
        WHERE k.confidence > 0
      `;
    }

    const rows = this.db.prepare(sql).all(...params) as KnowledgeRow[];
    return rows.map(r => this.rowToKnowledge(r));
  }

  /**
   * 查询某实体知道的所有活跃 Fact（过滤掉指向 contested/orphaned Fact 的 Knowledge）
   *
   * 用于检索管线 Step 5 的知识感知过滤。
   * JOIN facts 表确保只返回指向 canonical/potential Fact 的 Knowledge。
   */
  getActiveKnowledge(entityId: string, atChapter?: number): Knowledge[] {
    let sql: string;
    const params: unknown[] = [entityId];

    if (atChapter !== undefined) {
      sql = `
        SELECT k.* FROM knowledge k
        INNER JOIN facts f ON k.fact_id = f.id
        INNER JOIN (
          SELECT k2.entity_id, k2.fact_id, MAX(k2.known_since) as max_known, MAX(k2.rowid) as max_rowid
          FROM knowledge k2
          WHERE k2.entity_id = ? AND k2.known_since <= ?
          GROUP BY k2.entity_id, k2.fact_id
        ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
                  AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
        WHERE k.confidence > 0 AND f.certainty IN ('canonical', 'potential')
      `;
      params.push(atChapter);
    } else {
      sql = `
        SELECT k.* FROM knowledge k
        INNER JOIN facts f ON k.fact_id = f.id
        INNER JOIN (
          SELECT k2.entity_id, k2.fact_id, MAX(k2.known_since) as max_known, MAX(k2.rowid) as max_rowid
          FROM knowledge k2
          WHERE k2.entity_id = ?
          GROUP BY k2.entity_id, k2.fact_id
        ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
                  AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
        WHERE k.confidence > 0 AND f.certainty IN ('canonical', 'potential')
      `;
    }

    const rows = this.db.prepare(sql).all(...params) as KnowledgeRow[];
    return rows.map(r => this.rowToKnowledge(r));
  }

  /**
   * 查询某条 Fact 被哪些实体知晓（取最新一条认知记录，confidence > 0）
   */
  getKnowersOfFact(factId: string): Knowledge[] {
    const sql = `
      SELECT k.* FROM knowledge k
      INNER JOIN (
        SELECT entity_id, fact_id, MAX(known_since) as max_known, MAX(rowid) as max_rowid
        FROM knowledge
        WHERE fact_id = ?
        GROUP BY entity_id, fact_id
      ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
                AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
      WHERE k.confidence > 0
    `;
    const rows = this.db.prepare(sql).all(factId) as KnowledgeRow[];
    return rows.map(r => this.rowToKnowledge(r));
  }

  /**
   * 查询某 Fact 的全部认知记录（Retcon 级联扫描使用，含历史记录）
   *
   * 与 getKnowersOfFact 的区别：不过滤 confidence > 0，返回全部历史记录。
   */
  getByFactId(factId: string): Knowledge[] {
    const rows = this.db.prepare(
      'SELECT * FROM knowledge WHERE fact_id = ? ORDER BY known_since DESC, rowid DESC'
    ).all(factId) as KnowledgeRow[];
    return rows.map(r => this.rowToKnowledge(r));
  }

  /**
   * 更新确信度（作者订正时使用）
   *
   * ⚠ 不直接 UPDATE！遵循 Event Sourcing 原则：INSERT 新记录。
   * 通过 generateId 自动获取下一个可用序号。
   */
  updateConfidence(knowledgeId: string, confidence: number, updatedByEvent?: string): void {
    const existing = this.db.prepare('SELECT * FROM knowledge WHERE id = ?').get(knowledgeId) as KnowledgeRow | undefined;
    if (!existing) throw new Error(`KNOWLEDGE_NOT_FOUND: ${knowledgeId}`);

    // INSERT 新记录（confidence 变更，其他字段继承）
    // 委托 create 以复用 generateId 的消歧逻辑
    this.create({
      factId: existing.fact_id,
      entityId: existing.entity_id,
      knownSince: existing.known_since,
      source: existing.source as KnowledgeSource,
      confidence,
      previousConfidence: existing.confidence,
      updatedAtEvent: updatedByEvent ?? undefined,
    });
  }

  /**
   * 通用多条件查询
   */
  query(filter: KnowledgeFilter): Knowledge[] {
    const conditions: string[] = [];
    const params: unknown[] = [];

    if (filter.entityId) {
      conditions.push('entity_id = ?');
      params.push(filter.entityId);
    }
    if (filter.factId) {
      conditions.push('fact_id = ?');
      params.push(filter.factId);
    }
    if (filter.source && filter.source.length > 0) {
      conditions.push(`source IN (${filter.source.map(() => '?').join(',')})`);
      params.push(...filter.source);
    }
    if (filter.minConfidence !== undefined) {
      conditions.push('confidence >= ?');
      params.push(filter.minConfidence);
    }
    if (filter.atChapter !== undefined) {
      conditions.push('known_since <= ?');
      params.push(filter.atChapter);
    }

    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
    const rows = this.db.prepare(
      `SELECT * FROM knowledge ${whereClause} ORDER BY known_since DESC, rowid DESC`
    ).all(...params) as KnowledgeRow[];

    return rows.map(r => this.rowToKnowledge(r));
  }

  // -----------------------------------------------------------------------
  // 辅助方法
  // -----------------------------------------------------------------------

  /**
   * 生成 Knowledge ID：kno_{knower}_{factRef}[_{seq}]
   *
   * knower 为 entityId 去掉 ent_ 前缀的部分
   * factRef 为 factId 去掉 fct_ 前缀的部分
   *
   * 示例：
   *   首次：kno_claine_tribulation_50_01
   *   再次（seal/restore 等）：kno_claine_tribulation_50_01_02
   *
   * 消歧策略：同一 (entityId, factId) 组合首次写入直接用基础 ID；
   * 如果基础 ID 已存在（同章节内 seal/restore/decay 重复操作），
   * 追加两位数字序号（_02, _03...）。
   */
  private generateId(entityId: string, factId: string): string {
    const knower = entityId.replace('ent_', '');
    const factRef = factId.replace('fct_', '');
    const baseId = `kno_${knower}_${factRef}`;

    // 检查基础 ID 是否已占用
    const existing = this.db.prepare('SELECT COUNT(*) as cnt FROM knowledge WHERE id = ?').get(baseId) as { cnt: number };
    if (existing.cnt === 0) {
      return baseId;
    }

    // 基础 ID 已占用，追加序号
    let seq = 2;
    while (true) {
      const seqId = `${baseId}_${String(seq).padStart(2, '0')}`;
      const check = this.db.prepare('SELECT COUNT(*) as cnt FROM knowledge WHERE id = ?').get(seqId) as { cnt: number };
      if (check.cnt === 0) return seqId;
      seq++;
    }
  }

  /**
   * 将 SQLite 行转换为 Knowledge 对象
   */
  private rowToKnowledge(row: KnowledgeRow): Knowledge {
    return {
      id: row.id,
      factId: row.fact_id,
      entityId: row.entity_id,
      knownSince: row.known_since,
      source: row.source as KnowledgeSource,
      confidence: row.confidence,
      previousConfidence: row.previous_confidence ?? undefined,
      updatedAtEvent: row.updated_at_event ?? undefined,
    };
  }
}

// =============================================================================
// Narrative-OS-Core 核心类型定义
// =============================================================================
// 本文档是 Narrative-OS-Core 的单一类型真相源，定义了：
//   - 五大核心抽象的类型：Fact / NarrativeThread / Knowledge / ContextScope / Rule
//   - 所有适配器接口（FactStore / ThreadStore / KnowledgeStore / EventStore / VectorStore 等）
//   - LLM Tool Interface 的输入/输出类型（10 个 Tool）
//   - 错误编码体系（ToolError / ToolErrorCode）
//   - 辅助工具类型（序列化/反序列化、ID 生成等）
//
// 设计原则：
//   - 所有接口定义在此文件中，实现在各 adapters/ 目录
//   - 适配器接口只定义契约，不包含业务逻辑
//   - 领域类型使用 camelCase，LLM 外部接口使用 snake_case（由 Tool Interface 层转换）
// =============================================================================

// =============================================================================
// 第一部分：基础值类型
// =============================================================================

/**
 * Fact 的值类型：标量值或实体引用
 * 当前不支持数组或嵌套对象。有序列表应拆成多条 Fact 或使用 PredicateDefinition.sequenceOrder 表达顺序。
 */
export type FactValue = string | number | boolean | EntityRef;

/**
 * 关系 Fact 的目标引用 —— 表达 subject → targetEntity 的关系
 */
export interface EntityRef {
  type: 'entity_ref';
  entityId: string; // 如 'ent_lisi'
}

/**
 * Fact 值的 SQLite 序列化辅助：标记标量子类型，避免 "1"、1、true 反序列化混淆
 */
export type FactScalarType = 'string' | 'number' | 'boolean';

// =============================================================================
// 第二部分：确定性枚举
// =============================================================================

/**
 * Fact 的真实性状态
 *
 * 合法状态转换路径：
 *   canonical → contested   （Retcon 标记）
 *   canonical → orphaned    （上游依赖断裂）
 *   contested → canonical   （作者通过新 Fact 替代，不是直接 UPDATE）
 *   contested → orphaned    （作者确认放弃）
 *   potential → canonical   （沙盒推演确认提交）
 *   potential → orphaned    （沙盒推演被拒绝）
 *   orphaned  → canonical   （Retcon 撤回恢复依赖链）
 *
 * 简化：当前仅实现 potential→canonical 和 canonical→contested。
 * orphaned 相关转换推迟到后续迭代。
 */
export type Certainty = 'canonical' | 'contested' | 'potential' | 'orphaned';

// =============================================================================
// 第三部分：实体类型
// =============================================================================

/**
 * 实体分类（14 种），覆盖诡秘之主级别的设定复杂度
 *
 * 定位：EntityKind 是检索优化标签，不是世界本体论。
 * - 唯一用途：辅助 FactEmbedder 生成更精准的 embeddingText，辅助 RelevantFactRetriever 按类型过滤
 * - 不决定实体的行为、能力、关系——这些全部由 Fact 表达
 * - 新增 EntityKind 的门槛：必须有至少 3 部作品需要此类型来提升检索质量
 */
export type EntityKind =
  | 'entity'           // 实体：角色、物品等可独立存在的对象（通用兜底）
  | 'place'            // 地点：具体的地理位置或场所
  | 'spatial_domain'   // 空间域：抽象的空间范围或领域（如秘境、位面、灰雾之上）
  | 'state'            // 状态：封印状态、污染状态等可变化的状态实体
  | 'goal'             // 目标：角色、组织或世界阶段正在追求的结果
  | 'resource'         // 资源：货币、材料、线索、权柄等可消耗或争夺的对象
  | 'ability'          // 能力：技能、权限、仪式资格、序列能力等行动条件
  | 'identity'         // 身份：公开身份、隐藏身份、阵营身份、社会标签
  | 'theme'            // 主题：命运、代价、背叛等抽象叙事母题
  | 'rule'             // 规则：世界运行的法则、约束或机制
  | 'information'      // 信息：知识、情报、秘密等认知内容
  | 'foreshadowing'    // 伏笔：预先埋下的线索或暗示
  | 'event'            // 事件：已发生或正在发生的事情
  | 'time';            // 时间：时间点、时间段等时间相关概念

/**
 * 关系语义分类（15 种），作为 Fact 的可选元数据字段
 *
 * RelationKind 的推断优先级：
 *   1. 谓词映射表（确定性规则，如 enemy_of → social）
 *   2. LLM 标注（propose_event 时附加 relation_kind）
 *   3. 作者指定（对话中说明）
 */
export type RelationKind =
  | 'structural'      // 结构关系：组成、包含、分类等结构性连接
  | 'social'          // 社会关系：人际、组织、阵营等社会性连接
  | 'possession'      // 拥有关系：所有权、控制权、归属等
  | 'causal'          // 因果关系：导致、引发、影响等因果连接
  | 'informational'   // 信息关系：知晓、传播、隐藏等信息流动
  | 'spatial'         // 空间关系：位置、方向、距离等空间连接
  | 'temporal'        // 时间关系：先后、期限、周期、倒计时等时间连接
  | 'state'           // 状态关系：处于、感染、封印、激活等状态连接
  | 'goal'            // 目标关系：追求、阻碍、牺牲、完成等目标连接
  | 'dependency'      // 依赖关系：行动、知识、资源、条件之间的依赖连接
  | 'permission'      // 权限关系：允许、禁止、需要资格、可进入等许可连接
  | 'identity'         // 身份关系：伪装、真实身份、公开身份、隶属标签等连接
  | 'thematic'        // 主题关系：象征、映射、呼应、反讽等主题连接
  | 'rule'            // 规则关系：约束、限制、遵循等规则性连接
  | 'narrative';      // 叙事关系：伏笔照应、情节关联等叙事性连接

/**
 * 实体注册记录 —— 实体 ID 与元数据的映射
 */
export interface EntityRecord {
  id: string;              // 'ent_{name}[_{seq}]'
  name: string;            // 实体名称（拼音连写）
  kind: EntityKind;        // 实体分类
  description?: string;    // 自然语言描述
  registeredAtChapter: number;
  registeredAtEvent: string;
  tags?: string[];         // 作者自定义标签
}

// =============================================================================
// 第四部分：Fact 核心类型
// =============================================================================

/**
 * Fact：世界状态的最小原子单元，不可变
 *
 * 关系也是 Fact——没有独立的 GraphEdge 类型，关系通过 predicate 字段表达。
 * 所有世界状态统一为 (subject, predicate, value, time) 四元组。
 */
export interface Fact {
  id: string;              // 'fct_{type}_{chapter}[_{eventSeq}]_{factSeq}'
  subject: string;         // 主体实体 ID，如 'ent_zhangsan'
  predicate: string;       // 谓词：'realm' | 'enemy_of' | 'disciple_of' | ...
  value: FactValue;        // 值：标量或另一个实体的引用

  certainty: Certainty;    // 确定性标记
  causeEvent: string;      // 产生此事实的事件 ID（溯源核心）
  validFrom: number;       // 叙事生效章节号
  validTo: number | null;  // null = 当前仍有效

  relationKind?: RelationKind; // 关系语义类别（可选元数据）
  context: string;         // 作用域（默认 'global'），见 ContextScope
  embeddingText: string;   // 向量化输入文本，用于 LanceDB 语义检索
  schemaVersion: number;   // Fact 结构版本号，默认 1。用于 Schema Evolution 时按版本反序列化
}

/**
 * FactChange：引擎内部的 Fact 变更指令
 *
 * LLM 通过 Tool Interface 提交 FactChangeInput，系统在 propose_event 时将其转换为 FactChange。
 * 两者职责不同：FactChangeInput 追求 LLM 填写便利（snake_case），FactChange 保证引擎内部类型安全。
 */
export interface FactChange {
  changeId?: string;       // 对应 FactChangeInput.change_id，propose_event 阶段的临时 ID
  op: 'assert' | 'retract' | 'update';
  targetFactId?: string;   // retract / update 时必填，指定要操作的目标 Fact
  payload?: Partial<Omit<Fact, 'id' | 'causeEvent' | 'embeddingText'>>; // assert / update 时的新数据
}

/**
 * FactChangeInput：LLM 面向的外部接口（字段扁平、命名 snake_case）
 *
 * Tool Interface 层的转换引擎是通用函数（约 20 行），通过 FACT_CHANGE_MAPPING 声明式映射表转换。
 */
export interface FactChangeInput {
  change_id?: string;           // 变更临时 ID（可选，用于 knowledge_hints 引用）
  op: 'assert' | 'retract' | 'update';
  target_fact_id?: string;      // retract / update 时必填
  subject?: string;             // assert 时必填
  predicate?: string;           // assert 时可选（update 时若提供则变更）
  value?: FactValue;            // assert 时必填
  relation_kind?: RelationKind; // LLM 可选标注关系语义
  certainty?: Certainty;        // 默认 canonical，沙盒推演中为 potential
}

/**
 * FactGroup：一个 Event 产生的所有 FactChange 的原子集合
 *
 * 要么全部成功，要么全部回滚。
 */
export interface FactGroup {
  id: string;              // 与 causeEvent 一致，如 'evt_tribulation_50'
  causeEvent: string;      // 绑定的事件 ID（所有 Fact 的 causeEvent 都是这个）
  changes: FactChange[];   // 原子执行的变更集
}

/**
 * Fact 索引条目 —— LLM 执行 update/retract 操作的"手术刀柄"
 *
 * get_context_slice 返回此索引，LLM 从中提取 target_fact_id 执行后续操作。
 * ID 传递契约：LLM 严禁凭空捏造 Fact ID，必须从最近一次返回中提取。
 */
export interface FactIndexEntry {
  factId: string;          // 如 'fct_encounter_50_02'
  predicate: string;       // 如 'weapon'
  value: string;           // 如 '青竹蜂云剑'（已渲染为可读文本）
  validFrom: number;       // 如 50
  validTo: number | null;  // null = 当前仍有效
  isCurrent: boolean;      // true = 当前活跃状态
  context?: string;        // 所属作用域（非 global 时标注）
  action_hint?: string;    // 给 LLM 的防呆操作提示
}

// =============================================================================
// 第五部分：ContextScope 作用域
// =============================================================================

/**
 * ContextScope：作用域继承 + 遮蔽机制
 *
 * 处理副本、梦境、秘境、异世界等特殊空间中的状态隔离。
 * MVP 阶段统一为 context 字段处理。Phase 2 计划拆分为 Timeline + RealityLayer + ContextScope。
 *
 * 核心规则：
 *   - 进入作用域：设置 context 为非 global 值（如 arc_dream_01）
 *   - 退出作用域：作者逐条决定哪些 Fact 持久化到 global
 *   - 遮蔽机制：局部 Fact 遮蔽同 subject+predicate 的全局 Fact
 *   - 全局时间轴：所有作用域共享同一单调递增的章节号
 */
export interface ContextScopeConfig {
  name: string;                    // 作用域名称，如 'arc_dream_01'
  displayName: string;             // 人类可读名称
  parentContext: string;           // 父作用域（通常为 'global'）
  defaultExitBehavior: 'suggest_promote' | 'suggest_discard';
  worldPackageId?: string;         // 绑定的 World Package ID（可选）
  description?: string;
}

// =============================================================================
// 第六部分：NarrativeThread 叙事线索
// =============================================================================

/** 线索方向：回溯型（先写结果后补原因）还是渐进型（先埋种子后开花） */
export type ThreadDirection = 'retroactive' | 'progressive';

/** 线索类型 */
export type ThreadType =
  // 回溯型（原 Cost 类别）
  | 'causal_gap'           // 因果缺口：先写了结果，后需要补原因
  | 'timeline_perturbation' // 时间线扰动
  | 'rule_violation'       // 规则违反
  | 'logic_conflict'       // 逻辑矛盾
  // 渐进型（原 Foreshadowing 类别）
  | 'foreshadowing'        // 伏笔：预先埋下的线索或暗示
  | 'mystery'              // 谜团：尚未揭示的真相
  | 'prophecy'             // 预言：未来必然发生的事件
  | 'promise'              // 承诺：角色间或对读者的叙事期待
  | 'pattern';             // 模式：重复出现的规律等待最终解释

/** 线索状态 */
export type ThreadStatus =
  // 回溯型路径
  | 'UNFILLED'             // 结果已写，原因待补
  | 'FILLED'               // 原因已补完
  // 渐进型路径
  | 'PLANTED'              // 种子已埋下
  | 'HINTED'               // 再次暗示（可多次）
  | 'PARTIALLY_REVEALED'   // 部分揭示
  | 'RESOLVED'             // 完全回收/揭示
  // 共享终态
  | 'ABANDONED'            // 作者显式放弃
  | 'OBSOLETE';            // 上游依赖断裂

/** 叙事线索生命周期里程碑 */
export interface ThreadMilestone {
  id: string;
  status: ThreadStatus;
  chapter: number;
  eventId?: string;
  description: string;
  createdAt: string;       // ISO 8601
}

/**
 * NarrativeThread：统一追踪两类叙事承诺
 *
 * 设计意图：Cost 和 Foreshadowing 本质都是"对读者的叙事承诺，等待被兑现"。
 * 统一为 NarrativeThread 后，同一条线索可以同时是伏笔和规则违反。
 *
 * I-9 不变式（Thread Never Has Causal Power）：
 *   Thread 是 Fact 的观察层，不是世界状态的来源。
 *   - ✅ 允许：Fact/Event → Thread
 *   - ❌ 禁止：Thread → Fact / Thread → Knowledge
 */
export interface NarrativeThread {
  id: string;              // 'thr_{tag}_{chapter}[_{seq}]'
  type: ThreadType;
  direction: ThreadDirection;
  severity: 'minor' | 'major' | 'critical';
  description: string;

  closeCondition: {
    requiredEventType?: string;
    withinChapters?: number;
    customRule?: string;
    minHints?: number;     // 渐进型：至少暗示几次才能揭示
  };

  status: ThreadStatus;
  closedBy: string | null;
  createdAtEvent: string;
  createdAtChapter: number;
  milestones: ThreadMilestone[];
  relatedEntities: string[];   // 关联实体 ID 列表
  upstreamFactIds: string[];   // 上游依赖的 Fact ID 列表，用于 OBSOLETE 检测
  tags?: string[];             // 自由标签（如 ['side_arc', 'humor']）
  arcTag?: string;             // 关联的作用域名称（可选），用于主线写作时排除副本线索
}

// =============================================================================
// 第七部分：Knowledge 知识可见性
// =============================================================================

/**
 * 知识来源：角色获取这条知识的途径
 *
 * 分为四个梯队：
 *   第一梯队（写入时自动推导）：self_action / witnessed / faction_share
 *   第二梯队（需要独立事件触发）：informed / intelligence
 *   第三梯队（间接/不确定）：inferred / rumor / revelation
 *   第四梯队（认知层事件驱动）：memory_seal / memory_decay / memory_restore / implanted
 */
export type KnowledgeSource =
  // 第一梯队：写入时自动推导（Propagation Rules 产出）
  | 'self_action'        // 亲身经历：事件主体自动知晓（confidence 通常为 1.0）
  | 'witnessed'          // 直接目击：与事件主体同场景的实体自动知晓
  | 'faction_share'      // 组织共享：事件属于某阵营公开秘密，向成员广播
  // 第二梯队：需要独立事件触发
  | 'informed'           // 被告知：通过对话、信件、报告等主动传递
  | 'intelligence'       // 情报获取：通过占卜、监控、间谍等手段获取
  // 第三梯队：间接/不确定
  | 'inferred'           // 推断：角色根据已知信息逻辑推理得出
  | 'rumor'              // 传闻：通过非正式渠道获得的二手信息
  | 'revelation'         // 启示：通过超自然手段获得（奇幻/仙侠设定）
  // 第四梯队：认知层事件驱动
  | 'memory_seal'        // 记忆封印：confidence 被压至 0.0
  | 'memory_decay'       // 记忆衰退：confidence 按时间衰减公式降低
  | 'memory_restore'     // 记忆恢复：从封印状态恢复
  | 'implanted';          // 记忆植入：confidence 正常但内容可能为假

/**
 * Knowledge：角色对某条 Fact 的认知记录
 *
 * 与 Fact 的关系：Knowledge 不是 Fact 的修改，而是 Fact 之上的认知层。
 * 一条 Fact 可以被 0 个实体知晓（秘密），也可以被所有实体知晓（公开信息）。
 *
 * 硬边界：Knowledge 回答"实体 X 是否接触过 Fact Y，通过什么渠道，确信度多少？"
 * 不回答"是否真心相信"（Belief）、"认为别人怎么看"（Theory of Mind）。
 */
export interface Knowledge {
  id: string;              // 'kno_{knower}_{factSeq}'
  factId: string;          // 被知晓的 Fact ID
  entityId: string;        // 知晓者实体 ID（如 'ent_claine'）
  knownSince: number;      // 从哪个章节开始知道（支持小数编号）
  source: KnowledgeSource; // 知识来源
  confidence: number;      // 确信度 0.0-1.0
  previousConfidence?: number; // seal 操作前的 confidence 值，用于 restore 恢复
  updatedAtEvent?: string; // 最后更新此知识的事件 ID
}

/**
 * Knowledge 显式操作输入（由 propose_event 中的 knowledge_changes 驱动）
 *
 * LLM 不直接操作 Knowledge 表，而是通过事件间接触发。
 * Core 内部永远不 DELETE knowledge 表中的记录，只 INSERT 新记录。
 */
export interface KnowledgeChangeInput {
  op: 'seal' | 'restore' | 'decay' | 'soul_read' | 'implant';
  target_entity_id: string;          // 被操作的目标实体（如被搜魂者）
  fact_id_scope: 'all' | 'by_predicate' | 'by_time_range' | 'explicit';
  fact_ids?: string[];               // scope = explicit 时指定
  predicates?: string[];             // scope = by_predicate 时指定
  time_range?: { from: number; to: number }; // scope = by_time_range 时指定
  source_entity_id?: string;         // op = soul_read 时：施法者（获得知识的一方）
  implanted_confidence?: number;     // op = implant 时：植入的确信度
}

// =============================================================================
// 第八部分：NarrativeEvent 叙事事件
// =============================================================================

/**
 * 事件类型过滤
 */
export type EventKindFilter = 'business' | 'system' | 'all';

/**
 * NarrativeEvent：世界状态变更的唯一入口
 *
 * 核心原理：事件发生 → 改变世界状态 → 影响角色认知。
 * 每个 NarrativeEvent 同时改变客观世界状态和角色认知状态（双流写入）。
 */
export interface NarrativeEvent {
  id: string;                // 'evt_{type}_{chapter}[_{seq}]'
  kind: 'business' | 'system'; // business=剧情事件；system=Retcon/Schema 等审计锚点
  type: string;              // 事件类型，如 'tribulation' | 'ancient_encounter'
  chapter: number;           // 叙事章节（支持小数编号，DDL 列类型为 REAL）
  params: Record<string, unknown>;  // 事件参数，subject/target_event_id 等
  context: string;           // 事件发生的作用域，默认 'global'
  description: string;       // 自然语言摘要
  timestamp: string;         // 系统时间 ISO 8601（作者何时写的）
  factGroupId: string;       // 关联的 FactGroup ID（与事件 ID 相同，1:1）
  resolvedThreads: string[];  // 此事件关闭的 NarrativeThread ID 列表
  dependentFactIds: string[]; // 事件级依赖边的冗余快照，查询以 event_dependencies 表为准
}

// =============================================================================
// 第九部分：Rule Engine 类型
// =============================================================================

/**
 * 规则类型
 *
 * 排序按执行优先级：
 *   1. Transition  — detect pattern → generate consequence（可产生新 Fact）
 *   2. Inference   — detect pattern → derive new Fact
 *   3. Constraint  — prevent invalid state（纯判定，不产生新 Fact）
 *   4. Propagation — derive Knowledge from Event + entity relations
 */
export type RuleType = 'transition' | 'inference' | 'constraint' | 'propagation';

/**
 * 声明式规则定义（World Package 中存储的 JSON 格式规则）
 *
 * 规则通过 DeclarativeRuleEvaluator 解释执行，不包含可执行代码。
 * 对于超出声明式表达力的复杂规则，使用 TypeScript 硬编码规则（附录 H.5 第三层）。
 */
export interface DeclarativeRule {
  id: string;
  type: RuleType;
  name: string;
  description: string;
  priority: number;        // 规则优先级（同类型规则按 priority 升序执行）

  // 触发条件：声明式条件表达式
  conditions: RuleCondition[];

  // 规则产出
  consequences?: RuleConsequence[]; // Transition / Inference / Propagation 的产出

  // 约束规则特有
  violationMessage?: string;        // Constraint 违规时的错误消息
  violationSeverity?: 'minor' | 'major' | 'critical';

  // 传播规则特有
  propagationConfig?: PropagationConfig;
}

/**
 * 规则条件表达式
 */
export interface RuleCondition {
  type: 'subject_match' | 'predicate_match' | 'value_match' | 'entity_count' |
        'snapshot_gte' | 'snapshot_lte' | 'snapshot_sequence_jump' |
        'thread_count' | 'chapter_range';
  field?: string;          // 检查的字段
  operator?: 'eq' | 'neq' | 'gt' | 'gte' | 'lt' | 'lte' | 'in' | 'not_in';
  value?: unknown;         // 比较值
  conditions?: RuleCondition[]; // 嵌套条件（AND 逻辑）
}

/**
 * 规则产出
 */
export interface RuleConsequence {
  type: 'assert_fact' | 'create_thread' | 'propose_knowledge' | 'update_math';
  params: Record<string, unknown>;
}

/**
 * 知识传播配置
 */
export interface PropagationConfig {
  autoSubject?: boolean;         // 事件主体自动知晓
  witnessEntities?: boolean;     // 同场景目击传播
  factionShare?: boolean;        // 阵营广播
  witnessMaxDistance?: number;   // 目击传播的最大关联距离
}

/**
 * 事件后果：Rule Engine 沙盒推演的完整结果集
 */
export interface EventConsequence {
  generatedFacts: Fact[];               // 规则推导出的新事实（certainty='potential'）
  generatedThreads: NarrativeThread[];   // 违规/伏笔产生的叙事线索
  proposedKnowledge: ProposedKnowledge[]; // 知识传播规则建议的 Knowledge 条目
  warnings: string[];                   // 给 LLM 的警告信息（非阻塞）
}

/**
 * 建议的 Knowledge 条目（Rule Engine 沙盒推演产出）
 */
export interface ProposedKnowledge {
  entityId: string;          // 谁获得了新知识
  changeId: string;           // 对应 FactChangeInput.change_id（稳定引用，非数组下标）
  source: KnowledgeSource;    // 知识来源
  confidence: number;         // 确信度
  reason: string;             // 推导理由（展示在审计报告中，如"该角色与事件主体同在古墓"）
}

// =============================================================================
// 第十部分：World Package 类型
// =============================================================================

/**
 * World Package：一个完整的世界观配置
 *
 * Core 引擎是题材无关的通用框架。所有题材特定的规则、谓词映射、实体模板
 * 都通过 World Package 注入引擎。
 *
 * 不变式：World Package 是数据，不是代码。
 *   - ✅ 允许声明：谓词、关系映射、规则元数据、实体模板
 *   - ❌ 禁止执行：function / eval / execute 或任何可执行代码
 */
export interface WorldPackage {
  id: string;                    // 如 'xianxia_cultivation' | 'lotm_sequences'
  name: string;                  // 如 '仙侠修炼体系' | '诡秘序列体系'
  version: string;

  // 谓词注册表：定义这个世界观中合法的 predicate 及其中文标签
  predicates: PredicateDefinition[];

  // 规则集：这个世界观的状态转换规则、推理规则、约束规则、传播规则
  rules: RuleSet;

  // 谓词→关系语义映射：覆盖默认的 PREDICATE_RELATION_MAP
  predicateRelationMap: Record<string, RelationKind>;

  // 谓词→中文映射：覆盖默认的 PREDICATE_ZH_MAP
  predicateZhMap: Record<string, string>;

  // 实体模板：这个世界观中常见的实体类型预设
  entityTemplates?: EntityTemplate[];

  // 作用域预设：这个世界观中常见的作用域配置
  scopePresets?: ContextScopePreset[];

  // 谓词别名：旧名称 → 当前推荐名称。只影响新写入和渲染提示，不物理改写历史 Fact。
  predicateAliases?: Record<string, string>;
}

/**
 * 谓词定义：注册一个合法的 predicate
 */
export interface PredicateDefinition {
  name: string;            // 谓词名，如 'realm' | 'sequence' | 'spell_slot'
  displayName: string;     // 中文名，如 '修炼境界' | '序列' | '法术位'
  valueType: 'scalar' | 'entity_ref' | 'enum';
  enumValues?: string[];   // valueType='enum' 时的合法值列表
  sequenceOrder?: string[]; // 可选：有序枚举的递进序列（如 ['炼气','筑基','结丹','元婴']）
  description: string;      // 谓词的语义说明（帮助 LLM 理解）
  relationKind: RelationKind; // 默认的关系语义类别
  deprecated?: boolean;     // 旧谓词保留解释能力，但不再建议新 Fact 使用
  replacementPredicate?: string; // deprecated 时可选，指向推荐的新谓词
}

/**
 * 规则集
 */
export interface RuleSet {
  transitions: DeclarativeRule[];
  inferences: DeclarativeRule[];
  constraints: DeclarativeRule[];
  propagations: DeclarativeRule[];
}

/**
 * 实体模板：预定义常见实体类型的属性组合
 */
export interface EntityTemplate {
  kind: EntityKind;
  name: string;            // 模板名，如 'character_cultivator'
  extends?: string;        // 继承的父模板名
  defaultPredicates: string[]; // 此类实体通常有哪些 predicate
  overridePredicates?: Record<string, Partial<PredicateDefinition>>;
  description: string;
}

/**
 * 作用域预设：预定义常见的作用域配置
 */
export interface ContextScopePreset {
  name: string;            // 如 'dream' | 'dungeon' | 'legend_world'
  displayName: string;
  defaultExitBehavior: 'suggest_promote' | 'suggest_discard';
  inheritsGlobalRules: boolean;
  overrideRules?: RuleSet;
  description: string;
}

// =============================================================================
// 第十一部分：Tool Interface 输入/输出类型
