// =============================================================================
// 第十二部分：适配器接口
// =============================================================================

/**
 * FactStore：时序三元组存储层核心接口
 *
 * 以时间为第一维度的三元组存储，不是图数据库。
 * 四级索引：subject→predicate→Fact[] / causeEvent→Fact[] / factId→Fact / targetEntityId→Fact[]
 * 实现为 SQLiteFactStoreAdapter（better-sqlite3），接口层保持不变以便替换存储后端。
 */
export interface FactStore {
  // ---- 写入 ----
  assert(fact: Omit<Fact, 'id' | 'embeddingText'>): Fact;
  retract(factId: string, validTo: number): void;
  update(
    factId: string,
    newValue: FactValue,
    newCauseEvent: string,
    validFrom: number,
    context?: string
  ): Fact;
  applyFactGroup(group: FactGroup): Map<string, string>; // changeId → factId 映射
  forceRemove(factId: string): void; // 仅供事务回滚使用

  // ---- 查询 ----
  query(query: FactQuery): Fact[];
  getSnapshot(subject: string, atChapter: number): Record<string, FactValue>;
  getFactsByEvent(eventId: string): Fact[];
  getById(factId: string): Fact | undefined;
  getRelationsTargeting(entityId: string, atChapter?: number): Fact[];
}

/** Fact 查询条件 */
export interface FactQuery {
  subject?: string;
  predicate?: string;
  atChapter?: number;
  certainties?: Certainty[];
  relationKind?: RelationKind;
  valueEntityRef?: string;
  context?: string;
  includeInherited?: boolean;
  mode?: 'current' | 'history';
  includeInactive?: boolean;
}

/**
 * ThreadStore：叙事线索存储接口
 *
 * 与 FactStore 共享同一个 SQLite 连接（同库不同表），但接口层面职责完全分离。
 * NarrativeThread 与 Fact 本质不同：Fact 不可变，Thread 有状态流转和生命周期里程碑。
 */
export interface ThreadStore {
  create(thread: Omit<NarrativeThread, 'id'>): NarrativeThread;
  updateStatus(threadId: string, status: ThreadStatus, closedBy?: string): void;
  addMilestone(threadId: string, milestone: Omit<ThreadMilestone, 'id'>): void;
  getOpen(): NarrativeThread[];
  getById(threadId: string): NarrativeThread | undefined;
  getByFilters(filters: ThreadFilter): NarrativeThread[];
}

/** Thread 过滤条件 */
export interface ThreadFilter {
  direction?: ThreadDirection;
  type?: ThreadType[];
  severity?: ('minor' | 'major' | 'critical')[];
  status?: ThreadStatus[];
  nearChapter?: number;
  window?: number;
  closedByEvent?: string;
  relatedEntity?: string;
  arcTag?: string;
  excludeArcTags?: string[];
}

/**
 * KnowledgeStore：知识可见性存储接口
 *
 * 与 FactStore 共享同一个 SQLite 连接（同库不同表）。
 * Knowledge 遵循与 Fact 相同的 Event Sourcing 原则——不能删除，只能通过新事件覆盖或封印。
 */
export interface KnowledgeStore {
  create(knowledge: Omit<Knowledge, 'id'>): Knowledge;
  batchCreate(entries: Omit<Knowledge, 'id'>[]): Knowledge[];
  getKnownFacts(entityId: string, atChapter?: number): Knowledge[];
  getActiveKnowledge(entityId: string, atChapter?: number): Knowledge[];
  getKnowersOfFact(factId: string): Knowledge[];
  getByFactId(factId: string): Knowledge[];
  updateConfidence(knowledgeId: string, confidence: number, updatedByEvent?: string): void;
  query(filter: KnowledgeFilter): Knowledge[];
}

/** Knowledge 过滤条件 */
export interface KnowledgeFilter {
  entityId?: string;
  factId?: string;
  source?: KnowledgeSource[];
  minConfidence?: number;
  atChapter?: number;
}

/**
 * EventStore：事件存储接口
 *
 * Retcon BFS 级联遍历和事件溯源的前置依赖。
 * 与 FactStore 共享同一个 SQLite 连接，使用独立的 events 表。
 */
export interface EventStore {
  create(event: Omit<NarrativeEvent, 'id'>): NarrativeEvent;
  getById(eventId: string): NarrativeEvent | undefined;
  getByChapterRange(fromChapter: number, toChapter?: number, kind?: EventKindFilter): NarrativeEvent[];
  getBySubject(entityId: string, fromChapter?: number, kind?: EventKindFilter): NarrativeEvent[];
  getByType(eventType: string, fromChapter?: number, kind?: EventKindFilter): NarrativeEvent[];
  getByDependentFactIds(factIds: string[], kind?: EventKindFilter): NarrativeEvent[];
}

// =============================================================================
// 第十二点五部分：Phase 1.5A 叙事查询层
// =============================================================================

/** Entity 查询条件（Phase 1.5A 简版，直接读取 entities 表） */
export interface EntityFilter {
  id?: string;
  name?: string;
  nameContains?: string;
  kind?: EntityKind | EntityKind[];
  appearedBefore?: number;
  appearedAfter?: number;
}

/** Event 查询条件（Phase 1.5A 简版，封装 EventStore） */
export interface EventFilter {
  id?: string;
  type?: string;
  subject?: string;
  fromChapter?: number;
  toChapter?: number;
  kind?: EventKindFilter;
  dependentFactIds?: string[];
}

/** Fact 查询条件；Phase 1.5A 复用底层 FactQuery 语义 */
export type FactFilter = FactQuery;

/**
 * Knowledge 查询条件。
 *
 * 默认返回当前有效认知：对同一 (entityId, factId) 取最新记录，并过滤 confidence <= 0。
 * includeHistory=true 时返回历史记录；includeSealed=true 时保留 confidence=0 的封印记录。
 */
export interface NarrativeKnowledgeFilter extends KnowledgeFilter {
  factSubject?: string;
  factPredicate?: string;
  includeHistory?: boolean;
  includeSealed?: boolean;
}

/** Phase 1.5A 只读查询层；findThreads 等 Phase 2 ThreadStore 就绪后接入 */
export interface NarrativeQueryEngine {
  findFacts(filter: FactFilter): Promise<Fact[]>;
  findKnowledge(filter: NarrativeKnowledgeFilter): Promise<Knowledge[]>;
  findEvents(filter: EventFilter): Promise<NarrativeEvent[]>;
  findEntities(filter: EntityFilter): Promise<EntityRecord[]>;
}

/**
 * ProposalStore：提案存储接口
 *
 * Proposal 是 propose_event 和 commit_event 之间的临时数据。
 * 使用内存 Map 实现，进程重启后清空（LLM 需重新 propose）。
 */
export interface ProposalStore {
  save(proposal: ProposalResult, originalFactChanges?: FactChange[]): void;
  get(proposalId: string): ProposalResult | undefined;
  getOriginalChanges(proposalId: string): FactChange[];
  remove(proposalId: string): void;
  expireStale(currentChapter: number, maxAge?: number): void;
}

/**
 * VectorStore：向量存储接口
 *
 * LanceDB 的抽象接口，用于语义检索。
 * 实现为 LanceDBTableAdapter。
 */
export interface VectorStore {
  init(): Promise<void>;
  add(vectors: VectorEntry[]): Promise<void>;
  search(query: VectorQuery): Promise<ScoredFact[]>;
  markInvalid(factId: string): Promise<void>;
  updateCertainty(factId: string, certainty: Certainty): Promise<void>;
  remove(factId: string): Promise<void>;
  count(): Promise<number>;
  getAllIds(): Promise<string[]>;
}

/** 向量条目：写入 LanceDB 的数据结构 */
export interface VectorEntry {
  id: string;
  vector: number[];
  subject: string;
  predicate: string;
  valid_from: number;
  valid_to: number | null;
  is_current: boolean;
  certainty: Certainty;
  context: string;
}

/** 向量查询条件 */
export interface VectorQuery {
  embedding: number[];
  topK: number;
  filter?: {
    subject?: string;
    predicate?: string;
    context?: string;
    certainty?: Certainty;
    is_current?: boolean;
  };
}

/** 语义检索命中的 Fact（带相似度分数） */
export interface ScoredFact {
  factId: string;
  score: number;
}

// =============================================================================
// 第十三部分：嵌入与 LLM 服务接口
// =============================================================================

/**
 * EmbeddingService：文本向量化服务接口
 *
 * 默认实现使用硅基流动 BAAI/bge-m3（1024 维）。
 */
export interface EmbeddingService {
  embed(text: string): Promise<number[]>;
  embedBatch(texts: string[]): Promise<number[][]>;
}

/**
 * LLMClient：大语言模型客户端接口
 *
 * 默认实现使用 DeepSeek API（v4-flash / v4-pro）。
 * 用于 ContextAnalyzer 的深度分析模式（占 20% 调用量）。
 */
export interface LLMClient {
  chat(messages: ChatMessage[], options?: ChatOptions): Promise<string>;
  chatWithTools(messages: ChatMessage[], tools: ToolDefinition[], options?: ChatOptions): Promise<ToolCallResult>;
}

export interface ChatMessage {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

export interface ChatOptions {
  temperature?: number;
  max_tokens?: number;
  model?: string;
}

export interface ToolDefinition {
  name: string;
  description: string;
  parameters: Record<string, unknown>;
}

export interface ToolCallResult {
  content: string;
  toolCalls?: Array<{
    name: string;
    arguments: Record<string, unknown>;
  }>;
}

// =============================================================================
// 第十四部分：快照系统
// =============================================================================

/** 快照类型 */
export type SnapshotTriggerType = 'auto' | 'chapter' | 'pre_retcon' | 'major_event' | 'manual';

/** 世界状态快照元数据 */
export interface WorldSnapshot {
  id: string;              // 'snap_chapter_100'
  projectId: string;
  atChapter: number;
  triggerType: SnapshotTriggerType;
  createdAt: string;       // ISO 8601
  entityCount: number;
  factCount: number;
  storagePath: string;     // 'snapshots/{project_id}/snap_chapter_100.json'
}

/** 快照数据内容 */
export interface SnapshotData {
  atChapter: number;
  activeFacts: Array<{
    id: string;
    subject: string;
    predicate: string;
    value: FactValue;
    context: string;
    validFrom: number;
    causeEvent: string;
  }>;
  entities: Array<{
    id: string;
    name: string;
    kind: EntityKind;
  }>;
  openThreads: Array<{
    id: string;
    type: string;
    status: string;
  }>;
  activeKnowledge: Array<{
    id: string;
    entityId: string;
    factId: string;
    confidence: number;
    source: KnowledgeSource;
  }>;
}

// =============================================================================
// 第十五部分：同步队列
// =============================================================================

/** 同步队列操作类型 */
export type SyncQueueOperation = 'insert_vector' | 'mark_invalid' | 'update_certainty' | 'rebuild_event_vectors';

/** 同步队列条目 */
export interface SyncQueueEntry {
  eventId: string;
  factIds: string[];
  operation: SyncQueueOperation;
  payload: Record<string, unknown>;
  retryCount: number;
  maxRetries: number;
  nextRetryAt: number;
  error?: string;
}

// =============================================================================
// 第十六部分：ProjectSession 核心上下文
// =============================================================================

/**
 * ProjectSession：核心上下文对象
 *
 * 所有引擎组件共享同一个项目上下文，统一持有所有 Store 和服务实例，
 * 避免调用签名膨胀和实例版本不一致风险。
 */
export interface ProjectSession {
  projectId: string;
  factStore: FactStore;
  threadStore: ThreadStore;
  knowledgeStore: KnowledgeStore;
  eventStore: EventStore;
  proposalStore: ProposalStore;
  vectorStore: VectorStore;
  embedder: EmbeddingService;
  llm: LLMClient;
  worldPackage: WorldPackage;
}

// =============================================================================
// 第十七部分：错误编码体系
// =============================================================================

/**
 * Tool 错误码（20 个），覆盖所有已知的失败模式
 *
 * 分类：
 *   - 1000-1999: 验证错误
 *   - 2000-2999: 资源/状态冲突
 *   - 3000-3999: 系统错误
 */
export enum ToolErrorCode {
  // ---- 验证错误 (10xx) ----
  SCHEMA_VALIDATION_FAILED = 'SCHEMA_VALIDATION_FAILED',
  UNKNOWN_PREDICATE = 'UNKNOWN_PREDICATE',
  INVALID_ENUM_VALUE = 'INVALID_ENUM_VALUE',
  TYPE_MISMATCH = 'TYPE_MISMATCH',
  ENTITY_NOT_FOUND = 'ENTITY_NOT_FOUND',
  FACT_NOT_FOUND = 'FACT_NOT_FOUND',
  FACT_NOT_CURRENT = 'FACT_NOT_CURRENT',
  FACT_ID_FABRICATED = 'FACT_ID_FABRICATED',
  PROPOSAL_NOT_FOUND = 'PROPOSAL_NOT_FOUND',
  SCOPE_FACT_MISMATCH = 'SCOPE_FACT_MISMATCH',

  // ---- 冲突/逻辑错误 (20xx) ----
  PREDICATE_CONFLICT = 'PREDICATE_CONFLICT',
  STATE_VERSION_CONFLICT = 'STATE_VERSION_CONFLICT',
  STALE_PROPOSAL = 'STALE_PROPOSAL',
  LOGIC_CONFLICT = 'LOGIC_CONFLICT',
  RULE_VIOLATION = 'RULE_VIOLATION',
  SCOPE_RULE_VIOLATION = 'SCOPE_RULE_VIOLATION',

  // ---- 系统错误 (30xx) ----
  TRANSACTION_FAILED = 'TRANSACTION_FAILED',
  EMBEDDING_API_ERROR = 'EMBEDDING_API_ERROR',
  LANCEDB_ERROR = 'LANCEDB_ERROR',
  LLM_API_ERROR = 'LLM_API_ERROR',
}

/** 章节级别告警（非阻塞，但注入 LLM 提示） */
export type ChapterLevelWarning =
  | 'STALE_RETRIEVAL'       // 检索延迟 > 1s
  | 'LANCE_DB_DEGRADED'    // LanceDB 不可用
  | 'SPIKE_1_RECALL_LOW';  // 语义检索 Recall < 40%

/**
 * Tool 错误结果
 */
export interface ToolError {
  code: ToolErrorCode;
  message: string;
  detail?: string;          // 详细错误信息（如哪个字段校验失败）
  retryable: boolean;       // 是否可重试（L1 自修复判定依据）
  correctionHint?: string;  // 纠错指导（注入 LLM 的下一步建议）
}

/**
 * Tool 调用结果泛型：成功返回 T，失败返回 ToolError
 */
export type ToolResult<T> = { success: true; data: T } | { success: false; error: ToolError };

// =============================================================================
// 第十八部分：辅助工具函数类型
// =============================================================================

/**
 * FactChangeInput → FactChange 的声明式映射表
 *
 * 字段映射声明：外部 key（snake_case）→ 内部 key（camelCase）
 */
export const FACT_CHANGE_MAPPING = {
  fieldMap: {
    'change_id':      'changeId',
    'subject':        'subject',
    'predicate':      'predicate',
    'value':          'value',
    'target_fact_id': 'targetFactId',
  } as Record<string, string>,
  // 按 op 定义必填/可选字段
  opRules: {
    assert:  { required: ['subject', 'predicate', 'value'] },
    retract: { required: ['target_fact_id'] },
    update:  { required: ['target_fact_id'], optional: ['subject', 'predicate', 'value'] },
  } as Record<string, { required: string[]; optional?: string[] }>,
} as const;

// =============================================================================
// 第十九部分：序列化工具函数签名
// =============================================================================

/**
 * 将 FactValue 序列化为 SQLite 可存储的格式
 *
 * @param value - 原始 FactValue（string | number | boolean | EntityRef）
 * @returns { valueType: 'scalar' | 'entity_ref', scalarType?: FactScalarType, textValue: string }
 *   保证反序列化时能区分 "1"、1、true 三种不同类型
 */
export function serializeFactValue(value: FactValue): {
  valueType: 'scalar' | 'entity_ref';
  scalarType?: FactScalarType;
  textValue: string;
} {
  if (typeof value === 'object' && value !== null && (value as EntityRef).type === 'entity_ref') {
    return {
      valueType: 'entity_ref',
      textValue: (value as EntityRef).entityId,
    };
  }
  const jsType: FactScalarType = typeof value as FactScalarType;
  return {
    valueType: 'scalar',
    scalarType: jsType,
    textValue: String(value),
  };
}

/**
 * 从 SQLite 存储格式反序列化为 FactValue
 *
 * @param serialized - serializeFactValue 的返回值
 * @returns 原始 FactValue
 */
export function deserializeFactValue(serialized: {
  valueType: 'scalar' | 'entity_ref';
  scalarType?: FactScalarType;
  textValue: string;
}): FactValue {
  if (serialized.valueType === 'entity_ref') {
    return {
      type: 'entity_ref',
      entityId: serialized.textValue,
    } as EntityRef;
  }
  switch (serialized.scalarType) {
    case 'number':
      return Number(serialized.textValue);
    case 'boolean':
      return serialized.textValue === 'true';
    default:
      return serialized.textValue;
  }
}

