async findKnowledge(filter: NarrativeKnowledgeFilter): Promise<Knowledge[]> {
  const rows = filter.includeHistory
    ? this.knowledgeStore.query(filter)
    : this.getLatestKnowledge(filter);

  return rows.filter(knowledge => {
